package com.example.mfa.service;

import java.security.SecureRandom;
import java.util.ArrayList;
import java.util.HexFormat;
import java.util.List;

public class BackupCodeGenerator {
    private static final SecureRandom RNG = new SecureRandom();
    private static final HexFormat HEX = HexFormat.of();

    public static List<String> generateCodes(int count) {
        List<String> codes = new ArrayList<>(count);
        for (int i = 0; i < count; i++) {
            byte[] b = new byte[8];
            RNG.nextBytes(b);
            String raw = HEX.formatHex(b).toUpperCase();
            String code = raw.substring(0, 4) + "-" + raw.substring(4, 8) + "-" + raw.substring(8, 12) + "-" + raw.substring(12, 16);
            codes.add(code);
        }
        return codes;
    }

    public static String hint(String code) {
        String normalized = normalize(code);
        int len = normalized.length();
        if (len <= 4) return normalized;
        return normalized.substring(len - 4);
    }

    public static String normalize(String code) {
        if (code == null) return "";
        return code.replace("-", "").replace(" ", "").trim().toUpperCase();
    }
}

package com.example.mfa.service;

import com.example.mfa.model.AppUser;
import com.example.mfa.model.MfaBackupCode;
import com.example.mfa.repo.AppUserRepository;
import com.example.mfa.repo.MfaBackupCodeRepository;
import jakarta.servlet.http.HttpServletRequest;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Instant;
import java.util.ArrayList;
import java.util.List;

@Service
public class MfaBackupCodeService {

    private final AppUserRepository userRepository;
    private final MfaBackupCodeRepository codeRepository;
    private final PasswordEncoder passwordEncoder;

    public MfaBackupCodeService(AppUserRepository userRepository,
                                MfaBackupCodeRepository codeRepository,
                                PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.codeRepository = codeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public List<String> enableMfaAndGenerateBackupCodes(String username, String totpSecret, int count) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));

        user.setMfaEnabled(true);
        user.setTotpSecret(totpSecret);

        List<MfaBackupCode> existingUnused = codeRepository.findAllUnusedByUserId(user.getId());
        for (MfaBackupCode c : existingUnused) {
            c.setUsedAt(Instant.now());
            c.setUsedFromIp("SYSTEM");
            c.setUsedUserAgent("ROTATED");
        }

        List<String> rawCodes = BackupCodeGenerator.generateCodes(count);
        for (String raw : rawCodes) {
            String normalized = BackupCodeGenerator.normalize(raw);
            MfaBackupCode code = new MfaBackupCode();
            code.setUser(user);
            code.setCodeHash(passwordEncoder.encode(normalized));
            code.setCodeHint(BackupCodeGenerator.hint(normalized));
            codeRepository.save(code);
        }

        userRepository.save(user);
        return rawCodes;
    }

    @Transactional
    public List<String> rotateBackupCodes(String username, int count) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        if (!user.isMfaEnabled()) throw new IllegalStateException("MFA is not enabled");

        List<MfaBackupCode> existingUnused = codeRepository.findAllUnusedByUserId(user.getId());
        for (MfaBackupCode c : existingUnused) {
            c.setUsedAt(Instant.now());
            c.setUsedFromIp("SYSTEM");
            c.setUsedUserAgent("ROTATED");
        }

        List<String> rawCodes = BackupCodeGenerator.generateCodes(count);
        for (String raw : rawCodes) {
            String normalized = BackupCodeGenerator.normalize(raw);
            MfaBackupCode code = new MfaBackupCode();
            code.setUser(user);
            code.setCodeHash(passwordEncoder.encode(normalized));
            code.setCodeHint(BackupCodeGenerator.hint(normalized));
            codeRepository.save(code);
        }
        return rawCodes;
    }

    @Transactional
    public boolean consumeBackupCode(String username, String providedCode, HttpServletRequest request) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        if (!user.isMfaEnabled()) return false;

        String normalized = BackupCodeGenerator.normalize(providedCode);
        List<MfaBackupCode> unused = codeRepository.findUnusedByUserId(user.getId());
        for (MfaBackupCode c : unused) {
            if (passwordEncoder.matches(normalized, c.getCodeHash())) {
                MfaBackupCode locked = codeRepository.findByIdForUpdate(c.getId()).orElseThrow();
                if (locked.getUsedAt() != null) return false;
                locked.setUsedAt(Instant.now());
                locked.setUsedFromIp(clientIp(request));
                locked.setUsedUserAgent(userAgent(request));
                codeRepository.save(locked);
                return true;
            }
        }
        return false;
    }

    @Transactional(readOnly = true)
    public int remainingBackupCodes(String username) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        return codeRepository.findAllUnusedByUserId(user.getId()).size();
    }

    @Transactional(readOnly = true)
    public List<String> backupCodeHints(String username) {
        AppUser user = userRepository.findByUsername(username)
                .orElseThrow(() -> new IllegalArgumentException("User not found"));
        List<MfaBackupCode> unused = codeRepository.findAllUnusedByUserId(user.getId());
        List<String> hints = new ArrayList<>(unused.size());
        for (MfaBackupCode c : unused) {
            hints.add(c.getCodeHint());
        }
        return hints;
    }

    private static String userAgent(HttpServletRequest request) {
        if (request == null) return null;
        String ua = request.getHeader("User-Agent");
        if (ua == null) return null;
        return ua.length() > 255 ? ua.substring(0, 255) : ua;
    }

    private static String clientIp(HttpServletRequest request) {
        if (request == null) return null;
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isBlank()) {
            String first = xff.split(",")[0].trim();
            return first.length() > 64 ? first.substring(0, 64) : first;
        }
        String ip = request.getRemoteAddr();
        if (ip == null) return null;
        return ip.length() > 64 ? ip.substring(0, 64) : ip;
    }
}

package com.example.mfa.web;

import com.example.mfa.service.MfaBackupCodeService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.validation.constraints.Max;
import jakarta.validation.constraints.Min;
import jakarta.validation.constraints.NotBlank;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.validation.annotation.Validated;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@RestController
@RequestMapping("/api/mfa")
@Validated
public class MfaController {

    private final MfaBackupCodeService backupCodeService;

    public MfaController(MfaBackupCodeService backupCodeService) {
        this.backupCodeService = backupCodeService;
    }

    public record EnableMfaRequest(
            @NotBlank String username,
            @NotBlank String totpSecret,
            @Min(1) @Max(50) int backupCodeCount
    ) { }

    public record EnableMfaResponse(
            String username,
            boolean mfaEnabled,
            int remainingBackupCodes,
            List<String> backupCodes
    ) { }

    @PostMapping("/enable")
    public ResponseEntity<EnableMfaResponse> enable(@RequestBody @Validated EnableMfaRequest req) {
        List<String> codes = backupCodeService.enableMfaAndGenerateBackupCodes(req.username(), req.totpSecret(), req.backupCodeCount());
        int remaining = backupCodeService.remainingBackupCodes(req.username());
        return ResponseEntity.status(HttpStatus.CREATED).body(new EnableMfaResponse(req.username(), true, remaining, codes));
    }

    public record RotateBackupCodesRequest(
            @NotBlank String username,
            @Min(1) @Max(50) int backupCodeCount
    ) { }

    public record RotateBackupCodesResponse(
            String username,
            int remainingBackupCodes,
            List<String> backupCodes
    ) { }

    @PostMapping("/backup-codes/rotate")
    public ResponseEntity<RotateBackupCodesResponse> rotate(@RequestBody @Validated RotateBackupCodesRequest req) {
        List<String> codes = backupCodeService.rotateBackupCodes(req.username(), req.backupCodeCount());
        int remaining = backupCodeService.remainingBackupCodes(req.username());
        return ResponseEntity.status(HttpStatus.CREATED).body(new RotateBackupCodesResponse(req.username(), remaining, codes));
    }

    public record BackupCodeHintsResponse(
            String username,
            int remainingBackupCodes,
            List<String> hintsLast4
    ) { }

    @GetMapping("/backup-codes/hints")
    public ResponseEntity<BackupCodeHintsResponse> hints(@RequestParam("username") String username) {
        List<String> hints = backupCodeService.backupCodeHints(username);
        int remaining = backupCodeService.remainingBackupCodes(username);
        return ResponseEntity.ok(new BackupCodeHintsResponse(username, remaining, hints));
    }

    public record ConsumeBackupCodeRequest(
            @NotBlank String username,
            @NotBlank String backupCode
    ) { }

    public record ConsumeBackupCodeResponse(
            String username,
            boolean authenticated,
            int remainingBackupCodes
    ) { }

    @PostMapping("/backup-codes/authenticate")
    public ResponseEntity<ConsumeBackupCodeResponse> authenticateWithBackupCode(@RequestBody @Validated ConsumeBackupCodeRequest req,
                                                                              HttpServletRequest request) {
        boolean ok = backupCodeService.consumeBackupCode(req.username(), req.backupCode(), request);
        int remaining = backupCodeService.remainingBackupCodes(req.username());
        return ResponseEntity.ok(new ConsumeBackupCodeResponse(req.username(), ok, remaining));
    }
}

