package com.example.mfa.bootstrap;

import com.example.mfa.model.AppUser;
import com.example.mfa.repo.AppUserRepository;
import org.springframework.boot.CommandLineRunner;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

@Configuration
public class BootstrapData {
    @Bean
    CommandLineRunner seedUsers(AppUserRepository repo) {
        return args -> {
            if (repo.findByUsername("alice").isEmpty()) {
                AppUser u = new AppUser();
                u.setUsername("alice");
                u.setMfaEnabled(false);
                repo.save(u);
            }
            if (repo.findByUsername("bob").isEmpty()) {
                AppUser u = new AppUser();
                u.setUsername("bob");
                u.setMfaEnabled(false);
                repo.save(u);
            }
        };
    }
}

package com.example.mfa.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
public class SecurityConfig {
    @Bean
    SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
                .csrf(csrf -> csrf.disable())
                .authorizeHttpRequests(auth -> auth
                        .requestMatchers("/api/**").permitAll()
                        .anyRequest().authenticated()
                )
                .httpBasic(Customizer.withDefaults());
        return http.build();
    }
}

